+    /// Patterns commonly generated by ORMs: column aliasing, nested functions,
+    /// mixed aggregate/scalar in SELECT, and multi-table GROUP BY with HAVING.
+    #[test]
+    fn test_conformance_orm_patterns() {
+        let fconn = Connection::open(":memory:").unwrap();
+        let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+        let setup = [
+            "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT, email TEXT, created_at TEXT);",
+            "INSERT INTO users VALUES (1, 'Alice', 'alice@test.com', '2024-01-01');",
+            "INSERT INTO users VALUES (2, 'Bob', 'bob@test.com', '2024-02-15');",
+            "INSERT INTO users VALUES (3, 'Carol', 'carol@test.com', '2024-03-20');",
+            "CREATE TABLE orders (id INTEGER PRIMARY KEY, user_id INTEGER, amount REAL, status TEXT, created_at TEXT);",
+            "INSERT INTO orders VALUES (1, 1, 100.0, 'completed', '2024-01-15');",
+            "INSERT INTO orders VALUES (2, 1, 50.0, 'completed', '2024-02-01');",
+            "INSERT INTO orders VALUES (3, 2, 200.0, 'pending', '2024-02-20');",
+            "INSERT INTO orders VALUES (4, 2, 75.0, 'completed', '2024-03-01');",
+            "INSERT INTO orders VALUES (5, 3, 150.0, 'completed', '2024-03-25');",
+        ];
+        for s in &setup {
+            fconn.execute(s).unwrap();
+            rconn.execute_batch(s).unwrap();
+        }
+
+        let queries = [
+            // Aliased column in ORDER BY
+            "SELECT u.name AS user_name, count(o.id) AS order_count FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY order_count DESC",
+            // Sum with HAVING
+            "SELECT u.name, sum(o.amount) AS total FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name HAVING sum(o.amount) > 100 ORDER BY u.name",
+            // LEFT JOIN with aggregate (NULL handling)
+            "SELECT u.name, COALESCE(sum(o.amount), 0) AS total FROM users u LEFT JOIN orders o ON o.user_id = u.id AND o.status = 'completed' GROUP BY u.name ORDER BY u.name",
+            // Nested function in aggregate context
+            "SELECT u.name, count(CASE WHEN o.status = 'completed' THEN 1 END) AS completed_count FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY u.name",
+            // Subquery in FROM (derived table)
+            "SELECT sq.name, sq.total FROM (SELECT u.name, sum(o.amount) AS total FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name) sq ORDER BY sq.total DESC",
+            // CASE in GROUP BY result
+            "SELECT CASE WHEN count(o.id) > 1 THEN 'frequent' ELSE 'occasional' END AS buyer_type, count(*) AS cnt FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.id ORDER BY buyer_type",
+            // Multiple aggregates
+            "SELECT u.name, min(o.amount) AS min_order, max(o.amount) AS max_order, count(o.id) AS num_orders FROM users u JOIN orders o ON o.user_id = u.id GROUP BY u.name ORDER BY u.name",
+        ];
+
+        let mismatches = oracle_compare(&fconn, &rconn, &queries);
+        if !mismatches.is_empty() {
+            for m in &mismatches {
+                eprintln!("{m}\n");
+            }
+            panic!(
+                "{} ORM pattern conformance mismatches found",
+                mismatches.len()
+            );
+        }
+    }
