+    #[test]
+    fn test_conformance_window_functions() {
+        let fconn = Connection::open(":memory:").unwrap();
+        let rconn = rusqlite::Connection::open_in_memory().unwrap();
+
+        let setup = [
+            "CREATE TABLE emp (id INTEGER PRIMARY KEY, name TEXT, dept TEXT, salary INTEGER);",
+            "INSERT INTO emp VALUES (1, 'Alice', 'eng', 120);",
+            "INSERT INTO emp VALUES (2, 'Bob', 'eng', 100);",
+            "INSERT INTO emp VALUES (3, 'Carol', 'sales', 90);",
+            "INSERT INTO emp VALUES (4, 'Dave', 'sales', 80);",
+            "INSERT INTO emp VALUES (5, 'Eve', 'hr', 110);",
+            "INSERT INTO emp VALUES (6, 'Frank', 'hr', 95);",
+        ];
+        for s in &setup {
+            fconn.execute(s).unwrap();
+            rconn.execute_batch(s).unwrap();
+        }
+
+        let queries = [
+            // ROW_NUMBER
+            "SELECT name, dept, row_number() OVER (ORDER BY salary DESC) AS rn FROM emp ORDER BY rn",
+            // ROW_NUMBER with PARTITION BY
+            "SELECT name, dept, row_number() OVER (PARTITION BY dept ORDER BY salary DESC) AS rn FROM emp ORDER BY dept, rn",
+            // RANK
+            "SELECT name, salary, rank() OVER (ORDER BY salary DESC) AS rnk FROM emp ORDER BY rnk, name",
+            // DENSE_RANK
+            "SELECT name, salary, dense_rank() OVER (ORDER BY salary DESC) AS drnk FROM emp ORDER BY drnk, name",
+            // SUM window
+            "SELECT name, salary, sum(salary) OVER (ORDER BY id) AS running_total FROM emp ORDER BY id",
+            // COUNT window
+            "SELECT name, dept, count(*) OVER (PARTITION BY dept) AS dept_size FROM emp ORDER BY id",
+            // AVG window
+            "SELECT name, salary, avg(salary) OVER (PARTITION BY dept) AS dept_avg FROM emp ORDER BY id",
+        ];
+
+        let mismatches = oracle_compare(&fconn, &rconn, &queries);
+        if !mismatches.is_empty() {
+            for m in &mismatches {
+                eprintln!("{m}\n");
+            }
+            panic!(
+                "{} window function conformance mismatches found",
+                mismatches.len()
+            );
+        }
+    }
